@staticmethod
def _deep_merge(old_value, new_value):
    old_dict = old_value.feature if isinstance(old_value, Sequence) else old_value
    new_dict = new_value.feature if isinstance(new_value, Sequence) else new_value
    if isinstance(old_dict, dict) and isinstance(new_dict, dict):
        merged_dict = dict(old_dict)
        for sub_key, sub_value in new_dict.items():
            if sub_key in merged_dict:
                merged_dict[sub_key] = Features._deep_merge(merged_dict[sub_key], sub_value)
            else:
                merged_dict[sub_key] = sub_value
        if isinstance(old_value, Sequence):
            return Sequence(feature=merged_dict, length=old_value.length, id=old_value.id)
        if isinstance(new_value, Sequence):
            return Sequence(feature=merged_dict, length=new_value.length, id=new_value.id)
        return merged_dict
    return new_value

